package com.enterprise.auth.service;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AuthenticationException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.UUID;

@Service
public class UserService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;

    public UserService(UserRepository userRepository, PasswordEncoder passwordEncoder,
                       TotpService totpService, BackupCodeService backupCodeService,
                       AuditService auditService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
    }

    @Transactional
    public User registerUser(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }

        User user = new User();
        user.setUsername(request.getUsername());
        user.setPassword(passwordEncoder.encode(request.getPassword()));
        user.setEmail(request.getEmail());
        user.setMfaEnabled(false);

        User savedUser = userRepository.save(user);
        auditService.logAction(savedUser.getId(), "USER_REGISTERED", null, null, "User registered successfully", true);
        return savedUser;
    }

    public AuthenticationResponse login(LoginRequest request, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationException("Invalid username or password"));

        if (!passwordEncoder.matches(request.getPassword(), user.getPassword())) {
            auditService.logAction(user.getId(), "LOGIN_FAILED", ipAddress, userAgent, "Invalid password", false);
            throw new AuthenticationException("Invalid username or password");
        }

        AuthenticationResponse response = new AuthenticationResponse();
        response.setUsername(user.getUsername());

        if (user.isMfaEnabled()) {
            response.setMfaRequired(true);
            response.setAuthenticated(false);
            auditService.logAction(user.getId(), "LOGIN_MFA_REQUIRED", ipAddress, userAgent, "MFA verification required", true);
        } else {
            response.setMfaRequired(false);
            response.setAuthenticated(true);
            response.setToken(generateSimpleToken());
            auditService.logAction(user.getId(), "LOGIN_SUCCESS", ipAddress, userAgent, "Login successful (no MFA)", true);
        }

        return response;
    }

    @Transactional
    public MfaSetupResponse initiateMfaSetup(String username) {
        User user = findUserByUsername(username);

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this user");
        }

        String secret = totpService.generateSecret();
        user.setMfaSecret(secret);
        userRepository.save(user);

        String qrCodeUri = totpService.generateQrCodeUri(secret, username, "EnterpriseAuth");

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(secret);
        response.setQrCodeUri(qrCodeUri);

        auditService.logAction(user.getId(), "MFA_SETUP_INITIATED", null, null, "MFA setup initiated", true);
        return response;
    }

    @Transactional
    public MfaSetupResponse enableMfa(EnableMfaRequest request, String ipAddress, String userAgent) {
        User user = findUserByUsername(request.getUsername());

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this user");
        }

        if (user.getMfaSecret() == null) {
            throw new MfaException("MFA setup has not been initiated. Please initiate setup first.");
        }

        if (!totpService.verifyCode(user.getMfaSecret(), request.getTotpCode())) {
            auditService.logAction(user.getId(), "MFA_ENABLE_FAILED", ipAddress, userAgent, "Invalid TOTP code during MFA enable", false);
            throw new MfaException("Invalid TOTP code. Please try again.");
        }

        user.setMfaEnabled(true);
        userRepository.save(user);

        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(user.getMfaSecret());
        response.setQrCodeUri(totpService.generateQrCodeUri(user.getMfaSecret(), user.getUsername(), "EnterpriseAuth"));
        response.setBackupCodes(backupCodes);
        response.setTotalBackupCodes(backupCodes.size());

        auditService.logAction(user.getId(), "MFA_ENABLED", ipAddress, userAgent,
                "MFA enabled with " + backupCodes.size() + " backup codes generated", true);

        return response;
    }

    @Transactional
    public AuthenticationResponse verifyMfa(MfaVerificationRequest request, String ipAddress, String userAgent) {
        User user = findUserByUsername(request.getUsername());

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        if (!totpService.verifyCode(user.getMfaSecret(), request.getTotpCode())) {
            auditService.logAction(user.getId(), "MFA_VERIFICATION_FAILED", ipAddress, userAgent, "Invalid TOTP code", false);
            throw new AuthenticationException("Invalid TOTP code");
        }

        AuthenticationResponse response = new AuthenticationResponse();
        response.setUsername(user.getUsername());
        response.setMfaRequired(false);
        response.setAuthenticated(true);
        response.setToken(generateSimpleToken());
        response.setRemainingBackupCodes(backupCodeService.getRemainingCodesCount(user));

        auditService.logAction(user.getId(), "MFA_VERIFICATION_SUCCESS", ipAddress, userAgent, "TOTP verification successful", true);

        return response;
    }

    @Transactional
    public AuthenticationResponse verifyBackupCode(BackupCodeVerificationRequest request, String ipAddress, String userAgent) {
        User user = findUserByUsername(request.getUsername());

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        if (!backupCodeService.verifyBackupCode(user, request.getBackupCode())) {
            auditService.logAction(user.getId(), "BACKUP_CODE_VERIFICATION_FAILED", ipAddress, userAgent,
                    "Invalid or already used backup code", false);
            throw new AuthenticationException("Invalid or already used backup code");
        }

        long remainingCodes = backupCodeService.getRemainingCodesCount(user);

        AuthenticationResponse response = new AuthenticationResponse();
        response.setUsername(user.getUsername());
        response.setMfaRequired(false);
        response.setAuthenticated(true);
        response.setToken(generateSimpleToken());
        response.setRemainingBackupCodes(remainingCodes);

        auditService.logAction(user.getId(), "BACKUP_CODE_USED", ipAddress, userAgent,
                "Backup code used for authentication. Remaining: " + remainingCodes, true);

        return response;
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username, String ipAddress, String userAgent) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        List<String> newCodes = backupCodeService.generateBackupCodes(user);

        auditService.logAction(user.getId(), "BACKUP_CODES_REGENERATED", ipAddress, userAgent,
                "Backup codes regenerated. New count: " + newCodes.size(), true);

        return newCodes;
    }

    public BackupCodeStatusResponse getBackupCodeStatus(String username) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this user");
        }

        BackupCodeStatusResponse status = new BackupCodeStatusResponse();
        status.setTotalCodes(backupCodeService.getTotalCodesCount(user));
        status.setUsedCodes(backupCodeService.getUsedCodesCount(user));
        status.setRemainingCodes(backupCodeService.getRemainingCodesCount(user));

        return status;
    }

    @Transactional
    public void disableMfa(String username, String password, String ipAddress, String userAgent) {
        User user = findUserByUsername(username);

        if (!passwordEncoder.matches(password, user.getPassword())) {
            auditService.logAction(user.getId(), "MFA_DISABLE_FAILED", ipAddress, userAgent,
                    "Invalid password during MFA disable", false);
            throw new AuthenticationException("Invalid password");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        user.getBackupCodes().clear();
        userRepository.save(user);

        auditService.logAction(user.getId(), "MFA_DISABLED", ipAddress, userAgent, "MFA disabled", true);
    }

    private User findUserByUsername(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));
    }

    private String generateSimpleToken() {
        return UUID.randomUUID().toString() + "-" + UUID.randomUUID().toString();
    }
}

