package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final UserService userService;

    public AuthController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping("/register")
    public ResponseEntity<ApiResponse<Map<String, Object>>> register(@Valid @RequestBody RegisterRequest request) {
        User user = userService.registerUser(request);
        Map<String, Object> data = new HashMap<>();
        data.put("username", user.getUsername());
        data.put("email", user.getEmail());
        data.put("mfaEnabled", user.isMfaEnabled());
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(ApiResponse.success("User registered successfully", data));
    }

    @PostMapping("/login")
    public ResponseEntity<ApiResponse<AuthenticationResponse>> login(
            @Valid @RequestBody LoginRequest request, HttpServletRequest httpRequest) {
        AuthenticationResponse response = userService.login(request,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));
        return ResponseEntity.ok(ApiResponse.success("Login successful", response));
    }

    @PostMapping("/mfa/verify")
    public ResponseEntity<ApiResponse<AuthenticationResponse>> verifyMfa(
            @Valid @RequestBody MfaVerificationRequest request, HttpServletRequest httpRequest) {
        AuthenticationResponse response = userService.verifyMfa(request,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));
        return ResponseEntity.ok(ApiResponse.success("MFA verification successful", response));
    }

    @PostMapping("/mfa/backup-code/verify")
    public ResponseEntity<ApiResponse<AuthenticationResponse>> verifyBackupCode(
            @Valid @RequestBody BackupCodeVerificationRequest request, HttpServletRequest httpRequest) {
        AuthenticationResponse response = userService.verifyBackupCode(request,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));

        String message = "Backup code verification successful";
        if (response.getRemainingBackupCodes() != null && response.getRemainingBackupCodes() <= 3) {
            message += ". WARNING: Only " + response.getRemainingBackupCodes() + " backup codes remaining. Please regenerate.";
        }

        return ResponseEntity.ok(ApiResponse.success(message, response));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

