package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final UserService userService;

    public MfaController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping("/setup/{username}")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> initiateMfaSetup(@PathVariable String username) {
        MfaSetupResponse response = userService.initiateMfaSetup(username);
        return ResponseEntity.ok(ApiResponse.success(
                "MFA setup initiated. Scan the QR code and verify with a TOTP code to complete setup.", response));
    }

    @PostMapping("/enable")
    public ResponseEntity<ApiResponse<MfaSetupResponse>> enableMfa(
            @Valid @RequestBody EnableMfaRequest request, HttpServletRequest httpRequest) {
        MfaSetupResponse response = userService.enableMfa(request,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));
        return ResponseEntity.ok(ApiResponse.success(
                "MFA enabled successfully. Please save your backup codes securely. They will not be shown again.", response));
    }

    @PostMapping("/disable")
    public ResponseEntity<ApiResponse<Void>> disableMfa(
            @RequestBody Map<String, String> request, HttpServletRequest httpRequest) {
        String username = request.get("username");
        String password = request.get("password");
        userService.disableMfa(username, password,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));
        return ResponseEntity.ok(ApiResponse.success("MFA disabled successfully"));
    }

    @GetMapping("/backup-codes/status/{username}")
    public ResponseEntity<ApiResponse<BackupCodeStatusResponse>> getBackupCodeStatus(@PathVariable String username) {
        BackupCodeStatusResponse status = userService.getBackupCodeStatus(username);
        return ResponseEntity.ok(ApiResponse.success("Backup code status retrieved", status));
    }

    @PostMapping("/backup-codes/regenerate/{username}")
    public ResponseEntity<ApiResponse<Map<String, Object>>> regenerateBackupCodes(
            @PathVariable String username, HttpServletRequest httpRequest) {
        List<String> newCodes = userService.regenerateBackupCodes(username,
                getClientIp(httpRequest), httpRequest.getHeader("User-Agent"));

        Map<String, Object> data = Map.of(
                "backupCodes", newCodes,
                "totalCodes", newCodes.size(),
                "warning", "Previous backup codes have been invalidated. Save these new codes securely."
        );

        return ResponseEntity.ok(ApiResponse.success(
                "Backup codes regenerated successfully. Previous codes are now invalid.", data));
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

